import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';

/**
 * Helper to create an Order entity and save it to the repository.
 */
function createOrder(
  repo: OrderRepository,
  overrides: Partial<Order> & { id: string; userId: string },
): Order {
  const order: Order = {
    items: [],
    total: 0,
    status: 'pending',
    createdAt: new Date('2024-03-15T12:00:00Z'),
    updatedAt: new Date('2024-03-15T12:00:00Z'),
    ...overrides,
  };
  repo.save(order);
  return order;
}

/**
 * Helper to create a User entity and save it to the repository.
 */
function createUser(
  repo: UserRepository,
  overrides: Partial<User> & { id: string },
): User {
  const user: User = {
    name: 'Test User',
    email: 'test@example.com',
    role: 'member',
    createdAt: new Date('2024-03-01T00:00:00Z'),
    updatedAt: new Date('2024-03-01T00:00:00Z'),
    ...overrides,
  };
  repo.save(user);
  return user;
}

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  // Standard query covering March 2024
  const marchQuery: AnalyticsQuery = {
    startDate: '2024-03-01T00:00:00Z',
    endDate: '2024-04-01T00:00:00Z',
    granularity: 'day',
  };

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ─── getMetric ──────────────────────────────────────────────

  describe('getMetric', () => {
    it('should compute orders metric for a date range', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 50,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 30,
        createdAt: new Date('2024-03-20T10:00:00Z'),
      });

      const result = await service.getMetric('orders', marchQuery);

      expect(result.type).toBe('orders');
      expect(result.label).toBe('Total Orders');
      expect(result.current).toBe(2);
    });

    it('should compute revenue metric', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 50.5,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 30.25,
        createdAt: new Date('2024-03-20T10:00:00Z'),
      });

      const result = await service.getMetric('revenue', marchQuery);

      expect(result.type).toBe('revenue');
      expect(result.current).toBe(80.75);
    });

    it('should compute users metric', async () => {
      createUser(userRepo, {
        id: 'u1',
        name: 'Alice',
        email: 'alice@test.com',
        createdAt: new Date('2024-03-05T00:00:00Z'),
      });
      createUser(userRepo, {
        id: 'u2',
        name: 'Bob',
        email: 'bob@test.com',
        createdAt: new Date('2024-03-15T00:00:00Z'),
      });
      // Outside range
      createUser(userRepo, {
        id: 'u3',
        name: 'Charlie',
        email: 'charlie@test.com',
        createdAt: new Date('2024-04-05T00:00:00Z'),
      });

      const result = await service.getMetric('users', marchQuery);

      expect(result.type).toBe('users');
      expect(result.current).toBe(2);
    });

    it('should compute average-order-value metric', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 100,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 50,
        createdAt: new Date('2024-03-20T10:00:00Z'),
      });

      const result = await service.getMetric('average-order-value', marchQuery);

      expect(result.type).toBe('average-order-value');
      expect(result.current).toBe(75);
    });

    it('should calculate period-over-period comparison', async () => {
      // Previous period: Feb 1 - Mar 1 (auto-calculated from March query)
      createOrder(orderRepo, {
        id: 'o-prev',
        userId: 'u1',
        total: 100,
        createdAt: new Date('2024-02-15T10:00:00Z'),
      });
      // Current period: Mar 1 - Apr 1
      createOrder(orderRepo, {
        id: 'o-curr1',
        userId: 'u1',
        total: 80,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o-curr2',
        userId: 'u1',
        total: 120,
        createdAt: new Date('2024-03-20T10:00:00Z'),
      });

      const result = await service.getMetric('revenue', marchQuery);

      expect(result.current).toBe(200);
      expect(result.previous).toBe(100);
      expect(result.changePercent).toBe(100); // 100% increase
      expect(result.trend).toBe('up');
    });

    it('should return trend "down" for negative change', async () => {
      // Previous period has more revenue
      createOrder(orderRepo, {
        id: 'o-prev1',
        userId: 'u1',
        total: 200,
        createdAt: new Date('2024-02-15T10:00:00Z'),
      });
      // Current period has less revenue
      createOrder(orderRepo, {
        id: 'o-curr1',
        userId: 'u1',
        total: 100,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });

      const result = await service.getMetric('revenue', marchQuery);

      expect(result.trend).toBe('down');
      expect(result.changePercent).toBe(-50);
    });

    it('should return trend "flat" when no change', async () => {
      const result = await service.getMetric('orders', marchQuery);

      expect(result.current).toBe(0);
      expect(result.previous).toBe(0);
      expect(result.changePercent).toBe(0);
      expect(result.trend).toBe('flat');
    });

    it('should handle changePercent when previous is 0 but current > 0', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 50,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });

      const result = await service.getMetric('orders', marchQuery);

      expect(result.current).toBe(1);
      expect(result.previous).toBe(0);
      expect(result.changePercent).toBe(100);
    });

    it('should return 0 AOV when there are no orders in the period', async () => {
      const result = await service.getMetric('average-order-value', marchQuery);

      expect(result.current).toBe(0);
    });

    it('should round values to 2 decimal places', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 10,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 20,
        createdAt: new Date('2024-03-11T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o3',
        userId: 'u1',
        total: 30,
        createdAt: new Date('2024-03-12T10:00:00Z'),
      });

      const result = await service.getMetric('average-order-value', marchQuery);

      // (10 + 20 + 30) / 3 = 20 — but test with a trickier case
      expect(result.current).toBe(20);
    });

    it('should exclude orders outside the date range (boundary)', async () => {
      // Exactly at start (inclusive)
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 10,
        createdAt: new Date('2024-03-01T00:00:00Z'),
      });
      // Exactly at end (exclusive)
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 20,
        createdAt: new Date('2024-04-01T00:00:00Z'),
      });

      const result = await service.getMetric('orders', marchQuery);

      expect(result.current).toBe(1); // only o1, o2 is at boundary (exclusive)
    });
  });

  // ─── getTimeSeries ──────────────────────────────────────────

  describe('getTimeSeries', () => {
    it('should generate daily buckets for a date range', async () => {
      const shortQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-04T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getTimeSeries(shortQuery);

      expect(result).toHaveLength(3); // Mar 1, 2, 3
      expect(result[0].timestamp).toBe('2024-03-01T00:00:00.000Z');
      expect(result[1].timestamp).toBe('2024-03-02T00:00:00.000Z');
      expect(result[2].timestamp).toBe('2024-03-03T00:00:00.000Z');
    });

    it('should count orders in correct buckets', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        createdAt: new Date('2024-03-01T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        createdAt: new Date('2024-03-01T15:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o3',
        userId: 'u1',
        createdAt: new Date('2024-03-02T08:00:00Z'),
      });

      const shortQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-04T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getTimeSeries(shortQuery);

      expect(result[0].value).toBe(2); // Mar 1: o1, o2
      expect(result[1].value).toBe(1); // Mar 2: o3
      expect(result[2].value).toBe(0); // Mar 3: none
    });

    it('should fill empty buckets with 0', async () => {
      const shortQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-04T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getTimeSeries(shortQuery);

      expect(result).toHaveLength(3);
      for (const point of result) {
        expect(point.value).toBe(0);
      }
    });

    it('should generate hourly buckets', async () => {
      const hourQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-01T04:00:00Z',
        granularity: 'hour',
      };

      const result = await service.getTimeSeries(hourQuery);

      expect(result).toHaveLength(4); // 00, 01, 02, 03
    });

    it('should generate weekly buckets', async () => {
      const weekQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-22T00:00:00Z',
        granularity: 'week',
      };

      const result = await service.getTimeSeries(weekQuery);

      expect(result).toHaveLength(3); // 3 weeks
    });

    it('should generate monthly buckets', async () => {
      const monthQuery: AnalyticsQuery = {
        startDate: '2024-01-01T00:00:00Z',
        endDate: '2024-04-01T00:00:00Z',
        granularity: 'month',
      };

      const result = await service.getTimeSeries(monthQuery);

      expect(result).toHaveLength(3); // Jan, Feb, Mar
    });

    it('should return empty array when start equals end', async () => {
      const emptyQuery: AnalyticsQuery = {
        startDate: '2024-03-01T00:00:00Z',
        endDate: '2024-03-01T00:00:00Z',
        granularity: 'day',
      };

      const result = await service.getTimeSeries(emptyQuery);

      expect(result).toHaveLength(0);
    });
  });

  // ─── getTopProducts ─────────────────────────────────────────

  describe('getTopProducts', () => {
    it('should rank products by revenue', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 100,
        createdAt: new Date('2024-03-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 80 },
        ],
      });

      const result = await service.getTopProducts(marchQuery);

      expect(result).toHaveLength(2);
      expect(result[0].productId).toBe('p2'); // Gadget: $80
      expect(result[0].totalRevenue).toBe(80);
      expect(result[1].productId).toBe('p1'); // Widget: $20
      expect(result[1].totalRevenue).toBe(20);
    });

    it('should aggregate quantities and revenue across orders', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 20,
        createdAt: new Date('2024-03-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 30,
        createdAt: new Date('2024-03-15T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 },
        ],
      });

      const result = await service.getTopProducts(marchQuery);

      expect(result).toHaveLength(1);
      expect(result[0].totalQuantity).toBe(5);
      expect(result[0].totalRevenue).toBe(50);
    });

    it('should respect the limit parameter', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 60,
        createdAt: new Date('2024-03-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'A', quantity: 1, unitPrice: 10 },
          { productId: 'p2', name: 'B', quantity: 1, unitPrice: 20 },
          { productId: 'p3', name: 'C', quantity: 1, unitPrice: 30 },
        ],
      });

      const result = await service.getTopProducts(marchQuery, 2);

      expect(result).toHaveLength(2);
      expect(result[0].productId).toBe('p3'); // highest revenue
      expect(result[1].productId).toBe('p2');
    });

    it('should return empty array when no orders in range', async () => {
      const result = await service.getTopProducts(marchQuery);

      expect(result).toHaveLength(0);
    });

    it('should round totalRevenue to 2 decimal places', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 9.99,
        createdAt: new Date('2024-03-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 3.33 },
        ],
      });

      const result = await service.getTopProducts(marchQuery);

      expect(result[0].totalRevenue).toBe(9.99); // 3 * 3.33 = 9.99
    });
  });

  // ─── getRecentOrders ────────────────────────────────────────

  describe('getRecentOrders', () => {
    it('should return recent orders sorted by createdAt descending', async () => {
      createUser(userRepo, { id: 'u1', name: 'Alice', email: 'a@t.com' });
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 10,
        createdAt: new Date('2024-03-10T10:00:00Z'),
      });
      createOrder(orderRepo, {
        id: 'o2',
        userId: 'u1',
        total: 20,
        createdAt: new Date('2024-03-20T10:00:00Z'),
      });

      const result = await service.getRecentOrders(marchQuery);

      expect(result).toHaveLength(2);
      expect(result[0].orderId).toBe('o2'); // most recent first
      expect(result[1].orderId).toBe('o1');
    });

    it('should include userName from user repository', async () => {
