      for (let i = 1; i <= 5; i++) {
        createOrder(orderRepo, {
          id: `o${i}`,
          userId: 'u1',
          total: i * 10,
          createdAt: new Date(`2024-03-${String(i).padStart(2, '0')}T10:00:00Z`),
