      expect(result.timeSeries.length).toBeGreaterThan(0);
      expect(result.topProducts).toHaveLength(1);
      expect(result.recentOrders).toHaveLength(1);
      expect(result.generatedAt).toBeDefined();
    });

    it('should work with empty data', async () => {
      const result = await service.getDashboard(marchQuery);

      expect(result.metrics).toHaveLength(4);
      for (const metric of result.metrics) {
        expect(metric.current).toBe(0);
      }
      expect(result.topProducts).toHaveLength(0);
      expect(result.recentOrders).toHaveLength(0);
      expect(result.generatedAt).toBeDefined();
    });
  });

  // ─── Edge cases ─────────────────────────────────────────────

  describe('edge cases', () => {
    it('should handle a single data point', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 42,
        createdAt: new Date('2024-03-15T12:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 42 },
        ],
      });

      const metric = await service.getMetric('revenue', marchQuery);
      expect(metric.current).toBe(42);

      const topProducts = await service.getTopProducts(marchQuery);
      expect(topProducts).toHaveLength(1);
      expect(topProducts[0].name).toBe('Widget');
    });

    it('should handle large datasets', async () => {
      createUser(userRepo, { id: 'u1', name: 'Alice', email: 'a@t.com' });
      for (let i = 0; i < 100; i++) {
        const day = (i % 28) + 1;
        createOrder(orderRepo, {
          id: `o${i}`,
          userId: 'u1',
          total: 10 + i,
          createdAt: new Date(`2024-03-${String(day).padStart(2, '0')}T12:00:00Z`),
          items: [
            { productId: `p${i % 5}`, name: `Product ${i % 5}`, quantity: 1, unitPrice: 10 + i },
          ],
        });
      }

      const metric = await service.getMetric('orders', marchQuery);
      expect(metric.current).toBe(100);

      const topProducts = await service.getTopProducts(marchQuery, 3);
      expect(topProducts).toHaveLength(3);

      const recentOrders = await service.getRecentOrders(marchQuery, 5);
      expect(recentOrders).toHaveLength(5);
    });

    it('should handle orders with multiple items correctly in top products', async () => {
      createOrder(orderRepo, {
        id: 'o1',
        userId: 'u1',
        total: 150,
        createdAt: new Date('2024-03-10T10:00:00Z'),
        items: [
          { productId: 'p1', name: 'Widget', quantity: 5, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 50 },
        ],
      });

      const result = await service.getTopProducts(marchQuery);

      expect(result).toHaveLength(2);
      // Gadget: 2 * 50 = 100, Widget: 5 * 10 = 50
      expect(result[0].productId).toBe('p2');
      expect(result[0].totalRevenue).toBe(100);
      expect(result[1].productId).toBe('p1');
      expect(result[1].totalRevenue).toBe(50);
    });

    it('should handle narrow date range with no data', async () => {
      const narrowQuery: AnalyticsQuery = {
